class Solution:
    def reverseParentheses(self, s: str) -> str:
        stack = []
        for char in s:
            if char == '(':
                stack.append(char)
            elif char == ')':
                while stack[-1] != '(':
                    stack.pop()
                stack.pop()  
                s = s[:stack[-1] + 1] + s[stack[-1] + 1:][::-1]

            else:
                s = s[:stack[-1] + 1] + s[stack[-1] + 1:]
        return s
```
